SELECT

FROM ai_business_quantity_lock
WHERE tenant_id = #{tenantId}
  AND idempotency_key = #{idempotencyKey}
ORDER BY create_time DESC, id DESC
LIMIT 1

SELECT

FROM ai_business_quantity_lock
WHERE tenant_id = #{tenantId}
  AND lock_code = #{lockCode}
ORDER BY create_time DESC, id DESC
LIMIT 1

SELECT

FROM ai_business_quantity_lock
WHERE tenant_id = #{tenantId}
  AND account_code = #{accountCode}
  AND item_code = #{itemCode}
  AND dimension_key = #{dimensionKey}
  AND source_object_code = #{sourceObjectCode}
  AND source_record_id = #{sourceRecordId}
  AND lock_status = 'LOCKED'

  AND source_detail_id = #{sourceDetailId}


  AND source_detail_id IS NULL

ORDER BY create_time DESC, id DESC
LIMIT 1

mapper.update:
UPDATE ai_business_quantity_lock
SET released_quantity = released_quantity + #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{lockId}
  AND lock_status = 'LOCKED'
  AND lock_quantity - released_quantity - committed_quantity >= #{quantity}

UPDATE ai_business_quantity_lock
SET committed_quantity = committed_quantity + #{quantity},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{lockId}
  AND lock_status = 'LOCKED'
  AND lock_quantity - released_quantity - committed_quantity >= #{quantity}

UPDATE ai_business_quantity_lock
SET lock_status = #{lockStatus},
    update_time = NOW()
WHERE tenant_id = #{tenantId}
  AND id = #{lockId}
